export function dismissStartup() {
  const ov = document.getElementById('startup-screen');
  if (!ov) return;
  ov.classList.add('fade-out');
  ov.addEventListener('animationend', () => { ov.remove(); _showIntroTutorial(() => showClassScreen()); }, {once: true});
}

